#!/usr/bin/env python3
"""测试 SubagentStop hook - 验证 prompt 匹配方案"""
import sys
import json
from datetime import datetime

log_file = "/tmp/subagent-stop-test.log"

def get_subagent_type_by_prompt(agent_transcript_path: str, main_transcript_path: str) -> str | None:
    """通过 prompt 匹配获取 subagent_type"""
    # 1. 从 agent transcript 获取 prompt
    with open(agent_transcript_path, 'r') as f:
        first_line = f.readline()
        agent_first_msg = json.loads(first_line)
        prompt = agent_first_msg.get('message', {}).get('content', '')

    if not prompt:
        return None

    # 2. 在主会话中搜索匹配的 Task tool_use
    with open(main_transcript_path, 'r') as f:
        for line in f:
            if '"name":"Task"' not in line:
                continue
            try:
                msg = json.loads(line)
                for content in msg.get('message', {}).get('content', []):
                    if content.get('type') == 'tool_use' and content.get('name') == 'Task':
                        tool_prompt = content.get('input', {}).get('prompt', '')
                        if tool_prompt == prompt:
                            return content.get('input', {}).get('subagent_type')
            except:
                continue
    return None

def get_subagent_output(agent_transcript_path: str) -> str | None:
    """获取 subagent 的最终输出"""
    last_assistant_msg = None
    with open(agent_transcript_path, 'r') as f:
        for line in f:
            try:
                msg = json.loads(line)
                if msg.get('type') == 'assistant':
                    last_assistant_msg = msg
            except:
                continue

    if last_assistant_msg:
        content = last_assistant_msg.get('message', {}).get('content', [])
        if content and isinstance(content, list):
            for c in content:
                if c.get('type') == 'text':
                    return c.get('text')
    return None

# 主逻辑
input_data = sys.stdin.read()

with open(log_file, "a") as f:
    f.write(f"\n{'='*60}\n")
    f.write(f"Time: {datetime.now().isoformat()}\n")

    try:
        data = json.loads(input_data)
        agent_transcript_path = data.get('agent_transcript_path', '')
        main_transcript_path = data.get('transcript_path', '')

        # 验证 prompt 匹配方案
        subagent_type = get_subagent_type_by_prompt(agent_transcript_path, main_transcript_path)
        f.write(f"subagent_type (via prompt match): {subagent_type}\n")

        # 获取输出
        output = get_subagent_output(agent_transcript_path)
        f.write(f"subagent output: {output[:100] if output else None}...\n")

        f.write(f"\n✅ Prompt 匹配方案验证: {'成功' if subagent_type else '失败'}\n")

    except Exception as e:
        f.write(f"Error: {e}\n")
        import traceback
        f.write(traceback.format_exc())

sys.exit(0)
